var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"얘들아, 발밑 조심해. 어두워서 넘어질지도 몰라.","JPN":"みんな、足元に気をつけて。暗いから転ぶかもしれないよ。","ENG":"Girls, watch your step. It's dark, so you might trip and fall.","TWN":"大家，小心腳下。太黑了，可能會摔倒。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"여기 엄청 으스스한데…… 정말 괜찮을까?","JPN":"ここすごく不気味だけど……本当に大丈夫かな？","ENG":"It's really eerie here... Are you sure this is okay?","TWN":"這裡陰森森的……真的沒問題嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"걱정할 것 없어. 주변에 몬스터가 있다면, 내 드론이 전부 감지해 줄 거야.","JPN":"心配はいらないよ。周りにモンスターがいたら、ぼくのドローンが全部感知するから。","ENG":"There's nothing to worry about. If there are any monsters around here, my drone will detect them all.","TWN":"不用擔心，如果周圍有怪物，我的無人機會全部探測到。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"개량의 개량을 넘어, 이번엔 86% 완벽해!","JPN":"改良に改良を重ねて、今回は86％ぐらい完璧さ！","ENG":"After numerous modifications, it's now 86% perfect!","TWN":"超越改良的改良，這次達到了86%！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L11_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"조, 조금 애매하지 않아……?","JPN":"ちょ、ちょっと微妙じゃない……？","ENG":"I-isn't that percentage a little iffy...?","TWN":"有，有點模棱兩可吧……？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"걱정 말라니까 그러네. 우리 중 가장 강한 네가 이러면 안 되지.","JPN":"だから安心しなって。ぼくたちの中で君がいちばん強いのに弱音吐くなよ。","ENG":"Don't worry about it. You're the strongest out of all of us, so you should act braver.","TWN":"我說過不用擔心。我們中最強的你可不能這樣。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"이래선 최고의 히어로를 만났을 때 당당할 수 없잖아?","JPN":"これじゃ最高のヒーローに出会った時、堂々としていられないじゃん。","ENG":"You're not going to meet the best hero looking all scared, are you?","TWN":"遇到最強的英雄時就沒底氣了。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"걱정하지 마. 만약 위험해지면 내가 반드시 구해줄게!","JPN":"大丈夫。危なくなったら私が絶対助けてあげるから！","ENG":"Don't worry. If anything happens, I'll save you!","TWN":"別擔心，如果有危險，我一定會救你的！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"에헤헤, 시뮬레이션이니까 그럴 리는 없겠지만.","JPN":"えへへ、シミュレーションだからそんなことはないだろうけど。","ENG":"Although nothing will really happen because it's just a simulation, ehehe.","TWN":"嘿嘿嘿，雖然是模擬，但應該不會那樣吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"엇, 어떻게 된 거지?","JPN":"あっ、どうしたんだろ？","ENG":"Huh? What's this?","TWN":"咦，怎麼回事？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"감지가 통하지 않는 몬스터인 것 같아. 물러서 얘들아!","JPN":"感知できないモンスターみたい。みんな下がって！","ENG":"I think there's a monster that can't be detected. Girls, let's back off!","TWN":"好像是無法感知的怪物，大家退後！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아니, 나도 싸울게!","JPN":"ううん、あたしも戦う！","ENG":"No. I'll fight!","TWN":"不，我也要戰鬥！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"하아아앗!","JPN":"はああっ！","ENG":"Haaaaa!!!!","TWN":"哈啊啊啊！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"어라……?","JPN":"あれ……？","ENG":"Huh...?","TWN":"咦……？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흐응~ 누가 이렇게 쩔쩔매나 했는데 너희들이었어?","JPN":"ふーん、誰か慌てふためいてると思ったら、あんたたちだったの？","ENG":"Hmm...? I was wondering who was struggling over here. It's you girls?","TWN":"唔呼～我還在想是誰這麼狼狽，原來是你們啊？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"역시 최강의 랭커인 이 몸이 없으면 안 되는 모양이네.","JPN":"やっぱり最強のランカーであるナイエル様がいないとダメみたいね。","ENG":"I guess you'll need the best ranker to help you out, eh?","TWN":"果然沒有我這個最強高手是不行的呢。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L35_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"와~ 나이엘 선배!","JPN":"わ～ナイエル先輩！","ENG":"Wow! It's Naielle!","TWN":"哇～奈爾前輩！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"여어~ 오랜만이야 선배.","JPN":"お、久しぶり！　先輩。","ENG":"Yo! Long time no see, Naielle.","TWN":"唷呵～好久不見，前輩。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"정말 랭커가 되서 돌아온 거야?","JPN":"本当にランカーになって帰ってきたの？","ENG":"Are you really a top ranker now?","TWN":"真的成為高手回來啦？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하하, 당연하지. 카운터즈 레거시의 랭킹 2위! 나이엘 블루스틸이라구~","JPN":"あはは、当たり前でしょ。カウンターズ・レガシーのランキング2位！　ナイエル・ブルースチールよ～","ENG":"Haha! Of course! You're witnessing Counters Legacy's rank no. 2! Naielle Bluesteel!","TWN":"哈哈，當然了。我可是制裁者的遺產排名第二！奈爾·布魯斯提爾～"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"근데 너희들은 여기 왜 여깄어? 설마 아직도 그 히어로를 찾는 거야?","JPN":"で、あんたたちはなんでここにいるの？　まさかまだあのヒーローを探してるわけ？","ENG":"But why are you all here? Are you still looking for that best hero?","TWN":"不過你們為什麼在這裡？難道還在找那個英雄嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"당연하죠! 저흰 포기를 모르는 삼총사니까요!","JPN":"はい！　私たちは諦めを知らない3人組ですから！","ENG":"Yup! Because we're the trio that never gives up!","TWN":"當然了！我們可是從不放棄三劍客啊！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아참 선배! 그때 한 약속 기억하세요?","JPN":"あ、先輩！　あの時の約束、覚えてますか？","ENG":"Oh, right! Do you remember the promise you made, Naielle?","TWN":"對了，前輩！還記得那時候的約定嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"하트베리 퀘스트 하는 걸 도와주면 저희와 협력하겠다고 하셨잖아요.","JPN":"ハートベリーのクエストを手伝ったら、私たちに協力するって言ってくれたじゃないですか。","ENG":"You said you'd help us if we helped you with the HRT Berry quest.","TWN":"你不是說過如果幫你完成愛心莓果任務，就會和我們合作嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"잘하면 도와주겠다고 했지. 니들 완전히 허탕 쳤었잖아!","JPN":"上手くできたらでしょ。あんたたちは失敗したじゃない！","ENG":"I said that I'd help if you contributed. But you all did nothing!","TWN":"我說過如果你們做得好就會幫忙的。你們完全白費力氣了！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"에~ 그러기에요?","JPN":"え～そんな！","ENG":"Aww, seriously?","TWN":"啊～對吼？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"짠돌이! 만년 2등 랭커!","JPN":"ケチ！　万年2位ランカー！","ENG":"Cheapskate! You'll always just be ranked 2nd!","TWN":"小氣鬼！萬年老二！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"……치사해요.","JPN":"……ずるいです。","ENG":"...That's not fair.","TWN":"……真是卑鄙。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"시끄러! 2등은 아무나 하는 줄 알아!?","JPN":"うるさいわよ！　2位だって誰でもなれるものじゃないからね！","ENG":"Shut it! You think it's easy reaching rank 2?!","TWN":"閉嘴！你以為第二名是誰都能當的嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼 너희들. 그날 이후로 히어로에 대한 정보를 알아낸 게 있어?","JPN":"それならあんたたち、あの日以降何かヒーローについて新しい情報は手に入れたの？","ENG":"Anyway, did you get any more information about this hero since then?","TWN":"自那天之後，有打聽到關於英雄的消息嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하…… 너무 막연하잖아. 애초에 그 사람이 여기 있는 것도 확실치도 않고.","JPN":"はあ……漠然すぎるでしょ。そもそもその人がここにいる保証もないんでしょ？","ENG":"*Sigh* It's too reckless, then. We don't even know if this person is here in the first place.","TWN":"哈……太渺茫了吧，那個人在哪裡也不確定。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"저번에 이사장이 인정한 사람이라고 했지? 그럼 가서 직접 물어보던가!","JPN":"確か、理事長が認めた人って言ってたっけ？　じゃあ直接聞いてみればいいんじゃない？","ENG":"You said that he was acclaimed by the Chairwoman, right? Then just go ask her!","TWN":"你不是說上次理事長已經認可他了嗎？那就去親自問問吧！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저희도 몇 번이나 계속 물어봤는데, 매번 대답을 피하셨어요.","JPN":"何回も聞いてみましたけど、毎回はぐらかされました。","ENG":"We've asked several times, but she never gave us an answer.","TWN":"我們也問了好幾次，但每次都避而不答。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"얘들아. 그럼 지금이라도 다시 이사장님께…… 어?!","JPN":"みんな、そしたら今からでももう一度理事長に……あれ？","ENG":"Girls, let's just go ask the Chairwoman agai– Huh?!","TWN":"要不現在再去找一次理事長……嗯？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"어느새 몬스터들이 이렇게 다가온 거지? 내 드론의 감지율은 86%나 되는데……","JPN":"いつの間にモンスターたちがこんなに近くに……？　ぼくのドローンの感知率は86％もあるのに……","ENG":"When did the monsters get so close? My drone has an 86% detection rate...","TWN":"這些怪物什麼時候靠近的？我的無人機探測率可是有86%啊……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐야 그 애매한 확률은?!","JPN":"何よ、その曖昧な確率！？","ENG":"What kind of vague number is that?!","TWN":"什麼？這模棱兩可的機率是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"물러서 있어. 여기서 랭킹 2위의 실력을 보여줄 테니까!","JPN":"下がってなさい。ランキング2位の腕、見せてあげるわ！","ENG":"Stand back. I'll show you what being ranked 2nd looks like!","TWN":"退後，我會在這裡展示排名第二的實力！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};